/**
 * https://docs.cloud.google.com/run/docs/authenticating/service-to-service
 */
const { GoogleAuth } = require("google-auth-library");

const auth = new GoogleAuth();

function isLocalHttpBackend(url) {
  try {
    const u = new URL(url);
    return (
      u.protocol === "http:" &&
      (u.hostname === "localhost" || u.hostname === "127.0.0.1")
    );
  } catch {
    return false;
  }
}

/**
 * Cloud Run requires an OIDC identity token in Authorization.
 * The app JWT is forwarded in X-User-Authorization so backends can keep using req.headers.authorization.
 * Local HTTP backends skip OIDC; the browser's Authorization header is forwarded unchanged.
 */
async function attachInvokingIdentityHeaders(backendUrl, req) {
  if (isLocalHttpBackend(backendUrl)) {
    return;
  }
  const targetAudience = backendUrl.replace(/\/$/, "");
  const client = await auth.getIdTokenClient(targetAudience);
  const idToken = await client.idTokenProvider.fetchIdToken(targetAudience);
  const userAuth = req.headers.authorization;
  req.headers.authorization = `Bearer ${idToken}`;
  if (userAuth) {
    req.headers["x-user-authorization"] = userAuth;
  }
}

module.exports = { attachInvokingIdentityHeaders };

