Customer.sendinblue_webhook = async (req, result) => {
  let messageId = req.body['message-id']
  let email = req.body.email
  var url = `https://api.sendinblue.com/v3/smtp/emails?email=${email}&messageId=${messageId}&sort=desc&limit=500&offset=0`;
  const options = {
    method: 'GET',
    headers: {
      Accept: 'application/json',
      'api-key': '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'
    }
  };

  await fetch(url, options)
    .then(res => res.json())
    .then(async (json) => {
      url = "https://api.sendinblue.com/v3/smtp/emails/" + json.transactionalEmails[0].uuid;
      await fetch(url, options)
        .then(res => res.json())
        .then(async (json) => {
          //add 30 minutes to the sent date
          if (json) {
            let sentDate = new Date(json.date)
            sentDate.setMinutes(sentDate.getMinutes() + 30)
            let sentDateString = sentDate.toISOString();
            //await sendInBlueHelper.scheduledEmail([json.email, 'khu@edgeho.me'], json.body, json.subject, sentDateString)
            result(null, 200);
          } else {
            result(null, 'transactional not found');
          }

        })
        .catch(err => console.error('error:' + err));

