			});
			// Update existing rows whose stored modTime is older than the incoming row.
			await updateData(data.content, 'externalCustomer', 'customerCode');
			result(null, data.content)
		} else {
			result(null, 'No data was found')
		}
	} catch (err) {
		console.log(err)
		result(null, err);
	}
};

// Update each row by its own key, but only when the incoming record is newer
// (modTime greater than the stored value). One UPDATE per row, scoped to that row.
async function updateData(data, tableName, keyField) {
	for (let i = 0; i < data.length; i++) {
		const row = data[i];
		await sql[tableName].update(row, {
			where: {
				[keyField]: row[keyField],
				modTime: {
					[Op.lt]: row.modTime
				}
			}
		}).catch(err => {
			console.log(err)
		})
	}
}

