async verifyToken(token): Promise<boolean> {
    let isvalid = <boolean>await new Promise((resolve) => {
        this.http.get(this.serverAddress + `/verifyToken`, { headers: this.setUserAuth(token) }).subscribe({
            next: (data: any) => {
                if (data.status == "success" && !this.jwtHelper.isTokenExpired(token)) {
                    resolve(true);
                }
                else {
                    resolve(false);
                }
            },
            // Without this, any HTTP error (401/500/network) would leave the
            // promise unsettled and hang the route guard on a blank screen.
            error: () => resolve(false)
        })
    })
    return isvalid;
}

