ProdTracking.getViewlayout = async (req, result) => {
  try {
    var token = req.headers.authorization;
    let user = await getUserInfo(token)

    const data = await sql.GridAccessLevel.findAll({
      order: [Sequelize.literal('col_order ASC')],
      where: {

        grid_id: req.params.grid_id,
        access: true
      },
      include: [{
        model: sql.GridLayout,
        as: 'GridLayouts',
        where: {
          user_id_fk: null,
          layout_name: 'Default',
          grid_id: req.params.grid_id
        }
      }]
    })

    let newData = [];
    for (var i = 0; i < data.length; i++) {
      const layouts = data[i].dataValues.GridLayouts;
      // Guard against access rows that have no matching Default layout —
      // dereferencing GridLayouts[0] on an empty array threw and hung the request.
      if (layouts && layouts.length > 0) {
        newData.push(layouts[0].dataValues)
      }
    }
    result(null, newData)
  } catch (err) {
    console.log(err)
    result(err, null)
  }
}

