// Cache one IdTokenClient per target audience. Creating the client and the
// underlying ID token are both expensive (metadata-server round trips); the
// client also caches/refreshes the ~1h token internally, so reusing it avoids
// re-fetching a fresh token on every single proxied request.
const idTokenClients = new Map();

function getIdTokenClient(targetAudience) {
  let clientPromise = idTokenClients.get(targetAudience);
  if (!clientPromise) {
    clientPromise = auth.getIdTokenClient(targetAudience).catch((err) => {
      // Don't cache a rejected client — allow the next request to retry.
      idTokenClients.delete(targetAudience);
      throw err;
    });
    idTokenClients.set(targetAudience, clientPromise);
  }
