const crypto = require("crypto");

const API_KEY_HEADER = "x-api-key";
const DEFAULT_JWT_TTL = "1h";

function hashApiKey(apiKey) {
  return crypto.createHash("sha256").update(apiKey, "utf8").digest("hex");
}

function safeEqual(a, b) {
  const left = Buffer.from(String(a || ""), "utf8");
  const right = Buffer.from(String(b || ""), "utf8");
  return left.length === right.length && crypto.timingSafeEqual(left, right);
}

function parseDurationSeconds(value = DEFAULT_JWT_TTL) {
  const match = String(value).trim().match(/^(\d+)\s*(s|m|h|d)?$/i);
  if (!match) {
    throw new Error(`Invalid API_KEY_JWT_TTL: ${value}`);
  }

  const amount = Number(match[1]);
  const unit = (match[2] || "s").toLowerCase();
  const multipliers = { s: 1, m: 60, h: 60 * 60, d: 24 * 60 * 60 };
  return amount * multipliers[unit];
}

function base64url(input) {
  const buffer = Buffer.isBuffer(input) ? input : Buffer.from(JSON.stringify(input));
  return buffer
    .toString("base64")
    .replace(/=/g, "")
    .replace(/\+/g, "-")
    .replace(/\//g, "_");
}

function parseApiKeys(raw = process.env.DESIGNFLOW_API_KEYS) {
  if (!raw || !raw.trim()) {
    return [];
  }

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    throw new Error("DESIGNFLOW_API_KEYS must be valid JSON");
  }

  const entries = Array.isArray(parsed) ? parsed : [parsed];
  return entries.map((entry, index) => {
    const keyHash = entry.keyHash || (entry.key ? hashApiKey(entry.key) : null);
    const claims = entry.claims || {};

    if (!keyHash) {
      throw new Error(`DESIGNFLOW_API_KEYS[${index}] is missing keyHash`);
    }
    if (!claims.user_id || !claims.email || !claims.role) {
      throw new Error(`DESIGNFLOW_API_KEYS[${index}] claims require user_id, email, and role`);
    }

    return {
      name: entry.name || `api-key-${index + 1}`,
      keyHash,
      claims,
    };
  });
}

function findApiKeyEntry(apiKey, entries = parseApiKeys()) {
  const incomingHash = hashApiKey(apiKey);
  return entries.find((entry) => safeEqual(incomingHash, entry.keyHash));
}

function signInternalJwt(claims, options = {}) {
  const privateKey = options.privateKey || process.env.JWT_PRIVATE_KEY;
  if (!privateKey) {
    throw new Error("JWT_PRIVATE_KEY is required for API key authentication");
  }

  const now = Math.floor(Date.now() / 1000);
  const ttlSeconds = parseDurationSeconds(options.ttl || process.env.API_KEY_JWT_TTL || DEFAULT_JWT_TTL);
  const header = { alg: "RS256", typ: "JWT" };
  const payload = {
    ...claims,
    iat: now,
    exp: now + ttlSeconds,
    auth_type: "api_key",
  };

  const signingInput = `${base64url(header)}.${base64url(payload)}`;
  const signer = crypto.createSign("RSA-SHA256");
  signer.update(signingInput);
  signer.end();
  const signature = signer.sign(privateKey);

  return `${signingInput}.${base64url(signature)}`;
}

function apiKeyAuthMiddleware(req, res, next) {
  const apiKey = req.headers[API_KEY_HEADER];
  if (!apiKey) {
    return next();
  }

  let entry;
  try {
    entry = findApiKeyEntry(apiKey);
  } catch (err) {
    console.error("[BFF API key config error]", err.message);
    return res.status(500).json({ error: "API key authentication is misconfigured" });
  }

  if (!entry) {
    return res.status(401).json({ error: "Invalid API key" });
  }

  try {
    req.headers.authorization = signInternalJwt({
      ...entry.claims,
      api_key_name: entry.name,
    });
    delete req.headers[API_KEY_HEADER];
    return next();
  } catch (err) {
    console.error("[BFF API key auth error]", err.message);
    return res.status(500).json({ error: "API key authentication failed" });
  }
}

module.exports = {
  apiKeyAuthMiddleware,
  findApiKeyEntry,
  hashApiKey,
  parseApiKeys,
  signInternalJwt,
};

