// Bulk-archive the oldest N active RFQ items (admin-only). "Oldest" is ordered by
// COALESCE(rfqItem_date_modified, rfqItem_created_date) ASC, so rows that were never
// modified fall back to their creation date. Only flips the global
// rfqItem_archive flag on rows that are currently active (rfqItem_archive IS NULL),
// and is fully reversible via the existing un-archive path. Pass { dryRun: true } to
// preview the affected set without writing. limit defaults to 1500, capped at 5000.
Customer.archiveOldestRFQItems = async (req, result) => {
  const body = req.body || {}
  const requested = parseInt(body.limit, 10)
  const MAX_LIMIT = 5000
  const limit = Number.isFinite(requested) && requested > 0
    ? Math.min(requested, MAX_LIMIT)
    : 1500
  const dryRun = body.dryRun === true || body.dryRun === 'true'

  // COALESCE(date_modified, created_date) — the agreed "last changed" definition.
  const effectiveDateOrder = Sequelize.fn(
    'COALESCE',
    Sequelize.col('rfqItem_date_modified'),
    Sequelize.col('rfqItem_created_date')
  )

  const t = await sql.RFQItem.sequelize.transaction()
  try {
    const candidates = await sql.RFQItem.findAll({
      attributes: ['rfqItem_id', 'rfqItem_style_number', 'rfqItem_created_date', 'rfqItem_date_modified'],
      where: { rfqItem_archive: null },
      order: [[effectiveDateOrder, 'ASC']],
      limit,
      transaction: t,
    })

    if (dryRun) {
      await t.rollback()
      return result(null, {
        dryRun: true,
        limit,
        matched: candidates.length,
        items: candidates.map(c => ({
          rfqItem_id: c.rfqItem_id,
          rfqItem_style_number: c.rfqItem_style_number,
          effective_date: c.rfqItem_date_modified || c.rfqItem_created_date,
        })),
      })
    }

    const ids = candidates.map(c => c.rfqItem_id)
    let archived = 0
    if (ids.length > 0) {
      const [count] = await sql.RFQItem.update(
        { rfqItem_archive: 1 },
        { where: { rfqItem_id: { [Op.in]: ids } }, transaction: t }
      )
      archived = count
    }
    await t.commit()
    return result(null, { dryRun: false, limit, archived })
  } catch (err) {
    await t.rollback()
    return result(err, null)
  }
}

