const { describe, test, expect, beforeEach } = require('@jest/globals');

// Stub the sequelize package before the model module is loaded
jest.mock('sequelize', () => ({}), { virtual: true });

describe('customers model definition', () => {
  const modelFactory = require('../../models/db/customers');

  const DataTypes = {
    STRING: Object.assign((n) => ({ _type: 'STRING', length: n }), { _type: 'STRING' }),
    INTEGER: { _type: 'INTEGER' },
    DATE: { _type: 'DATE' },
    TEXT: { _type: 'TEXT' },
  };

  let capturedName;
  let capturedAttrs;
  let capturedOpts;

  const fakeSequelize = {
    define: (name, attrs, opts) => {
      capturedName = name;
      capturedAttrs = attrs;
      capturedOpts = opts;
      return { name, attrs, opts };
    },
  };

  beforeEach(() => {
    capturedName = undefined;
    capturedAttrs = undefined;
    capturedOpts = undefined;
    modelFactory(fakeSequelize, DataTypes);
  });

  test('model is named customers', () => {
    expect(capturedName).toBe('customers');
  });

  test('has customers_logo field', () => {
    expect(capturedAttrs).toHaveProperty('customers_logo');
  });

  test('customers_logo allows null', () => {
    expect(capturedAttrs.customers_logo.allowNull).toBe(true);
  });

  test('has required primary key field customers_id', () => {
    expect(capturedAttrs).toHaveProperty('customers_id');
    expect(capturedAttrs.customers_id.primaryKey).toBe(true);
  });

  test('has customers_name field', () => {
    expect(capturedAttrs).toHaveProperty('customers_name');
  });

  test('has customers_dilution field', () => {
    expect(capturedAttrs).toHaveProperty('customers_dilution');
  });

