'use strict';

const { Op } = require('sequelize');
const { archiveStaleVendorQuotes } = require('../../helpers/archive-stale-quotes');

function makeSql() {
  return {
    RFQVendor: {
      update: jest.fn().mockResolvedValue([0]),
    },
  };
}

describe('archiveStaleVendorQuotes', () => {
  afterEach(() => jest.clearAllMocks());

  test('does nothing and returns 0 when factoryId is falsy', async () => {
    const sql = makeSql();
    const count = await archiveStaleVendorQuotes(sql, undefined);
    expect(count).toBe(0);
    expect(sql.RFQVendor.update).not.toHaveBeenCalled();
  });

  test('sets RFQVendor_archived=true scoped to the factory', async () => {
    const sql = makeSql();
    sql.RFQVendor.update.mockResolvedValue([5]);

    const count = await archiveStaleVendorQuotes(sql, 31);

    expect(count).toBe(5);
    expect(sql.RFQVendor.update).toHaveBeenCalledTimes(1);
    const [values, options] = sql.RFQVendor.update.mock.calls[0];
    expect(values).toEqual({ RFQVendor_archived: true });
    expect(options.where.vendor_id_fk).toBe(31);
  });

  test('only targets priced, quoted, active, not-opted-out rows', async () => {
    const sql = makeSql();
    await archiveStaleVendorQuotes(sql, 31);
    const { where } = sql.RFQVendor.update.mock.calls[0][1];

    // price provided (not null AND not empty)
    expect(where.RFQVendor_amount[Op.and]).toEqual([{ [Op.ne]: null }, { [Op.ne]: '' }]);
    // quoted, and older than the threshold
    expect(where.quote_date[Op.ne]).toBeNull();
    expect(where.quote_date[Op.lt]).toBeDefined();
    // IS NOT TRUE guards (match both false and null): not already archived, no pending
    // re-quote request, and the vendor has not manually opted out.
    expect(where.RFQVendor_archived[Op.not]).toBe(true);
    expect(where.requote_requested[Op.not]).toBe(true);
    expect(where.RFQVendor_archive_optout[Op.not]).toBe(true);
  });

  test('threshold months are coerced into the SQL interval (no injection)', async () => {
    const sql = makeSql();
    await archiveStaleVendorQuotes(sql, 31, '6; DROP TABLE');
    const { where } = sql.RFQVendor.update.mock.calls[0][1];
    // Number('6; DROP TABLE') === NaN, so the literal never carries raw input.
    const literalSql = where.quote_date[Op.lt].val;
    expect(literalSql).toContain('CURRENT_DATE - INTERVAL');
    expect(literalSql).not.toContain('DROP TABLE');
  });

  test('defaults to a 3 month threshold', async () => {
    const sql = makeSql();
    await archiveStaleVendorQuotes(sql, 31);
    const { where } = sql.RFQVendor.update.mock.calls[0][1];
    expect(where.quote_date[Op.lt].val).toContain("INTERVAL '3 months'");
  });
});

