'use strict';

const { Op, fn, col } = require('sequelize');

const DEFAULT_LIMIT = 1500;
const MAX_LIMIT = 5000;

/**
 * Bulk-archive the oldest N active RFQ items.
 *
 * "Oldest" is ordered by COALESCE(rfqItem_date_modified, rfqItem_created_date) ASC,
 * so rows that were never modified fall back to their creation date. Only rows that
 * are currently active (rfqItem_archive IS NULL) are considered, and the operation
 * is fully reversible via the existing un-archive path (set rfqItem_archive back to
 * null). The find + update run in a single transaction so the rows previewed are the
 * rows archived.
 *
 * @param {object} sql - models object; must expose RFQItem (with .sequelize).
 * @param {object} [opts]
 * @param {number} [opts.limit=1500] - how many to archive (clamped to [1, 5000]).
 * @param {boolean} [opts.dryRun=false] - when true, return the matched set without writing.
 * @returns {Promise<object>} dryRun ? { dryRun, limit, matched, items } : { dryRun, limit, archived }
 */
async function archiveOldestRFQItems(sql, opts = {}) {
  const requested = parseInt(opts.limit, 10);
  const limit = Number.isFinite(requested) && requested > 0
    ? Math.min(requested, MAX_LIMIT)
    : DEFAULT_LIMIT;
  const dryRun = opts.dryRun === true || opts.dryRun === 'true';

  // The agreed "last changed" definition: last modified, else created.
  const effectiveDateOrder = fn('COALESCE', col('rfqItem_date_modified'), col('rfqItem_created_date'));

  const t = await sql.RFQItem.sequelize.transaction();
  try {
    const candidates = await sql.RFQItem.findAll({
      attributes: ['rfqItem_id', 'rfqItem_style_number', 'rfqItem_created_date', 'rfqItem_date_modified'],
      where: { rfqItem_archive: null },
      order: [[effectiveDateOrder, 'ASC']],
      limit,
      transaction: t,
    });

    if (dryRun) {
      await t.rollback();
      return {
        dryRun: true,
        limit,
        matched: candidates.length,
        items: candidates.map((c) => ({
          rfqItem_id: c.rfqItem_id,
          rfqItem_style_number: c.rfqItem_style_number,
          effective_date: c.rfqItem_date_modified || c.rfqItem_created_date,
        })),
      };
    }

    const ids = candidates.map((c) => c.rfqItem_id);
    let archived = 0;
    if (ids.length > 0) {
      const [count] = await sql.RFQItem.update(
        { rfqItem_archive: 1 },
        { where: { rfqItem_id: { [Op.in]: ids } }, transaction: t }
      );
      archived = count;
    }
    await t.commit();
    return { dryRun: false, limit, archived };
  } catch (err) {
    await t.rollback();
    throw err;
  }
}

module.exports = { archiveOldestRFQItems, DEFAULT_LIMIT, MAX_LIMIT };

