'use strict';

const { Op } = require('sequelize');
const {
  archiveOldestRFQItems,
  DEFAULT_LIMIT,
  MAX_LIMIT,
} = require('../../helpers/archive-oldest-rfq');

function makeSql(candidates = []) {
  const transaction = {
    commit: jest.fn().mockResolvedValue(undefined),
    rollback: jest.fn().mockResolvedValue(undefined),
  };
  const sql = {
    RFQItem: {
      sequelize: { transaction: jest.fn().mockResolvedValue(transaction) },
      findAll: jest.fn().mockResolvedValue(candidates),
      update: jest.fn().mockResolvedValue([candidates.length]),
    },
  };
  return { sql, transaction };
}

const row = (id, modified, created) => ({
  rfqItem_id: id,
  rfqItem_style_number: `STYLE-${id}`,
  rfqItem_date_modified: modified,
  rfqItem_created_date: created,
});

describe('archiveOldestRFQItems', () => {
  afterEach(() => jest.clearAllMocks());

  test('only considers active rows (rfqItem_archive IS NULL)', async () => {
    const { sql } = makeSql([row(1, '2024-01-01', '2023-01-01')]);
    await archiveOldestRFQItems(sql, {});
    const { where } = sql.RFQItem.findAll.mock.calls[0][0];
    expect(where).toEqual({ rfqItem_archive: null });
  });

  test('defaults to DEFAULT_LIMIT when no limit supplied', async () => {
    const { sql } = makeSql([]);
    const res = await archiveOldestRFQItems(sql, {});
    expect(sql.RFQItem.findAll.mock.calls[0][0].limit).toBe(DEFAULT_LIMIT);
    expect(res.limit).toBe(DEFAULT_LIMIT);
  });

  test('clamps limit to MAX_LIMIT', async () => {
    const { sql } = makeSql([]);
    await archiveOldestRFQItems(sql, { limit: 999999 });
    expect(sql.RFQItem.findAll.mock.calls[0][0].limit).toBe(MAX_LIMIT);
  });

  test('coerces a numeric-string limit and respects it', async () => {
    const { sql } = makeSql([]);
    await archiveOldestRFQItems(sql, { limit: '25' });
    expect(sql.RFQItem.findAll.mock.calls[0][0].limit).toBe(25);
  });

  test('archives the matched ids with rfqItem_archive=1 and commits', async () => {
    const candidates = [row(1, '2024-01-01', null), row(2, null, '2023-06-01')];
    const { sql, transaction } = makeSql(candidates);
    sql.RFQItem.update.mockResolvedValue([2]);

    const res = await archiveOldestRFQItems(sql, { limit: 2 });

    const [values, options] = sql.RFQItem.update.mock.calls[0];
    expect(values).toEqual({ rfqItem_archive: 1 });
    expect(options.where.rfqItem_id[Op.in]).toEqual([1, 2]);
    expect(transaction.commit).toHaveBeenCalledTimes(1);
    expect(transaction.rollback).not.toHaveBeenCalled();
    expect(res).toEqual({ dryRun: false, limit: 2, archived: 2 });
  });

  test('does not call update when nothing matches', async () => {
    const { sql, transaction } = makeSql([]);
    const res = await archiveOldestRFQItems(sql, {});
    expect(sql.RFQItem.update).not.toHaveBeenCalled();
    expect(transaction.commit).toHaveBeenCalledTimes(1);
    expect(res.archived).toBe(0);
  });

  test('dryRun rolls back, never updates, and returns the matched preview', async () => {
    const candidates = [row(7, '2024-02-02', '2023-02-02')];
    const { sql, transaction } = makeSql(candidates);

    const res = await archiveOldestRFQItems(sql, { dryRun: true });

    expect(sql.RFQItem.update).not.toHaveBeenCalled();
    expect(transaction.rollback).toHaveBeenCalledTimes(1);
    expect(transaction.commit).not.toHaveBeenCalled();
    expect(res.dryRun).toBe(true);
    expect(res.matched).toBe(1);
    expect(res.items[0]).toEqual({
      rfqItem_id: 7,
      rfqItem_style_number: 'STYLE-7',
      effective_date: '2024-02-02',
    });
  });

  test('dryRun preview falls back to created_date when modified is null', async () => {
    const { sql } = makeSql([row(9, null, '2023-09-09')]);
    const res = await archiveOldestRFQItems(sql, { dryRun: true });
    expect(res.items[0].effective_date).toBe('2023-09-09');
  });

  test('rolls back and rethrows if the update fails', async () => {
    const { sql, transaction } = makeSql([row(1, '2024-01-01', null)]);
    sql.RFQItem.update.mockRejectedValue(new Error('db down'));

    await expect(archiveOldestRFQItems(sql, {})).rejects.toThrow('db down');
    expect(transaction.rollback).toHaveBeenCalledTimes(1);
    expect(transaction.commit).not.toHaveBeenCalled();
  });
});

