  // Start loader immediately to prevent blank page flash
  this.loaderService.increment();

  this.authService.getUserFromToken().then((user: any) => {
    this.currentUserId = user?.user_id ?? null;
  });

  this.setupVendorSubscription();
  this.verifyRole();
  this.loadCompanyCode();
}

private getMerchGroupDivisionCodes(): number[] {
  const divisions = this.getMerchGroupDivisions();
  return divisions
    .map((division) => division.divCode_id)
    .filter((id): id is number => id != null);
}

private getMerchGroupDivisions(): RfqMerchGroupDivision[] {
  if (!this.selectedDivisionCode) {
    return [];
  }
  return Array.isArray(this.selectedDivisionCode)
    ? this.selectedDivisionCode
    : [this.selectedDivisionCode];
}

private getRfqStatusToActiveValidationContext(): RfqStatusToActiveValidationContext {
  return {
    exemptUserIds: this.allowActiveWithoutTechPackUserIds,
    currentUserId: this.currentUserId,
    requiredFields: this.getActiveStatusRequiredFields(),
    merchGroupDivisionCodes: this.getMerchGroupDivisionCodes(),
    merchGroupDivisions: this.getMerchGroupDivisions(),
  };
}

private notifyRfqItemStatusChanged(
  newStatus: { title?: string } | string | null | undefined,
  rowData?: Record<string, unknown> | null
): void {
  const rawTitle = typeof newStatus === 'string' ? newStatus : newStatus?.title;
  const title = rawTitle?.trim();
  if (!title) {
    return;
  }
  const normalized = title.toLowerCase();
  if (normalized !== 'active' && normalized !== 'inactive' && normalized !== 'draft') {
    return;
  }
  const priceCode =
    rowData?.['Price Code'] ??
    (this.getMasterFiledName('price_code') ? rowData?.[this.getMasterFiledName('price_code')] : undefined);
  const itemLabel =
    priceCode != null && String(priceCode).trim() ? ` for ${priceCode}` : '';
  this._snackBar.open(`RFQ status updated to ${title}${itemLabel}.`, 'Close', {
    duration: 5000,
    verticalPosition: 'bottom',
    horizontalPosition: 'center',
  });
}

private formatNumber(number: number): string {
  return Number.parseFloat(String(number))
    .toFixed(2)
    .replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1,');
}

percentFormatter = (params) =>
  params?.value ? `${this.formatNumber(params.value)}%` : '';

currencyFormatter = (params) =>
  params?.value ? `$${this.formatNumber(params.value)}` : '';

formatedDate(input: any): string {
  return input ? formatDate(input, 'MM/dd/yyyy', 'en-US') : '';
}

private afterMetadataReady(): void {
  this.verifyVendorMode();
  this.getLicenseList();
  this.getCBM();
  this.getAllRFQItem();
}

private loadRFQStatuses(): void {
  this.itemService.getRFQItemStatus().subscribe((res: any) => {
    // Store status list for clipboard operations
    this.statusList = res || [];
    this.prepareDivisionStatus(res);
    this.getRFQGroup();
    this.loadCustomers();
    this.loadDeliveryLocations();
    this.loadRFQSteps();

    if (this.selectedDivisionCode && this.selectedDivisionCodeStatus) {
     this.afterMetadataReady();
    }
  });
}

private loadRFQSteps(): void {
  this.itemService.getRFQStep().subscribe((data: any[]) => {
    // Store step list for clipboard operations (separate from status)
    this.stepList = data || [];
    // Pre-populate autocomplete cache so the first Step cell click is instant.
    if (data?.length && !window['rfq-autocomplete']?.step?.options) {
      if (!window['rfq-autocomplete']) window['rfq-autocomplete'] = {};
      window['rfq-autocomplete'].step = {
        options: data.map((d: any) => ({ title: d.RFQStep_title, id: d.RFQStep_id }))
      };
    }
  });
}

private prepareDivisionStatus(res: any[]): void {
  this.selectedDivisionCodeStatus = [];

  if (this.role !== 'vendor') {
    this.selectedDivisionCodeStatus.push(res[0]);
    if (this.role === 'designer') {
      this.selectedDivisionCodeStatus.push(res[2]);
    }
  } else {
    this.selectedDivisionCodeStatus = res;
  }

  this.divisionCodeStatus = [...res];
  window['selectedDivisionCodeStatus'] = this.selectedDivisionCodeStatus;
}

private setupVendorSubscription(): void {
  onSetVendorData.subscribe(data => {
    this.rowData = this.rowData.map(item => {
      if (item.id === data.row_id) {
        item.Vendors = item.Vendors.map(vendor =>
          vendor.id === data.Vendor.id ? data : vendor
        );
      }
      return item;
    });
  });
}

private handleCompanyCode(data: any[]): void {
  this.selectedCompanyCode = data[0].company_name;
  this.companyCode = data;

  this.selectedDivisionCode = data[0].divisionCodes;
  this.divisionCode = data[0].divisionCodes;

  window['selectedDivisionCode'] = this.selectedDivisionCode;
}

getRFQGroup(){
  this.itemService.getRFQGroup().subscribe(async (data: any) => {
    // Store both string array and object array for clipboard operations
    this.RFQGroupListObjects = data || [];
    for (var i = 0; data.length > i; i++) {
      this.RFQGroupList[i] = data[i].RFQGroup_name
    }
  });
}

verifyRole(){
  this.itemService.verifyRole().subscribe(res => {
    this.role = res.role
    window['role'] = this.role
    this.access = res.access
    if (this.role == 'vendor') {
      this.detailRowHeight = 108
    }
    // Role arrives async; first paint may have skipped default Step filter — re-apply when grid exists.
    if (this.gridApi) {
      this.applyDefaultStepFilter(() => {
        this.applyRfqMasterDetailExpansionDefaults(this.gridApi);
        setTimeout(() => this.applyRfqMasterDetailExpansionDefaults(this.gridApi), 0);
      });
    }
  })
}

private loadCompanyCode(): void {
  this.itemService.getCompanyCode().subscribe((data: any) => {
    this.handleCompanyCode(data);
    this.loadRFQStatuses();
  });
}

private loadCustomers(): void {
  this.itemService.getCustomers().subscribe((data: any[]) => {
    // Store full customer list for clipboard operations
    this.customerList = data || [];
  });
}

private loadDeliveryLocations(): void {
  this.itemService.getDeliveryLocation().subscribe((data: any[]) => {
    // Store full delivery location list for clipboard operations
    this.deliveryLocationList = data || [];
  });
}

getLicenseList(){
  this.itemService.getLicenseList().subscribe((licenses: any[]) => {
    this.licenseRateMap = {};
    if (Array.isArray(licenses)) {
      for (let i = 0; i < licenses.length; i++) {
        const t = licenses[i].licenseList_title;
        const key = (t ?? '').toString().trim().toLowerCase();
        if (key) this.licenseRateMap[key] = {
          royalty_rate: licenses[i].licenseList_royalty_rate ?? 0,
          fob_royalty_rate: licenses[i].licenseList_fob_royalty_rate ?? 0,
        };
      }
    }
  })
}

getCBM(){
  this.itemService.getCBM().subscribe(async (data: any) => {
    for (var i = 0; data.length > i; i++) {
      this.cbmOptions.push({ title: data[i].RFQContainer_price, id: data[i].RFQContainer_id })
    }
  })
}

private renameProductFields(columns: any[]) {
  const fieldMap = {
    Material: { field: 'Product Type', headerName: 'Product Type' },
    Construction: { field: 'Product Sub-Type', headerName: 'Product Sub-Type' },
    Treatment: { field: 'Product Sub-Sub-Type', headerName: 'Product Sub-Sub-Type' }
  };

  return columns.map(col =>
    fieldMap[col.field] ? { ...col, ...fieldMap[col.field] } : col
  );
}

private applyAutoFormatters(columns: any[]) {
  return columns.map(col => {
    if (!col.field?.toLowerCase().includes('date')) return col;
    const updated: any = { ...col, valueFormatter: this.dateFormatter };
    // Resolve the comparator string to the actual function — the config
    // stores "dateComparator" as a string which AG-Grid cannot call as a function.
    // NOTE: No aggFunc — postSortRows handles group ordering by newest child date.
    // Adding aggFunc to ANY column activates AG-Grid's aggregation pipeline for
    // group rows which interferes with valueSetter/onCellValueChanged for calculated
    // columns (FOB Cost, CBM/pc, Landed Cost, etc.).
    if (col.field === 'Date Modified') {
      updated.comparator = this.dateComparator.bind(this);
    }
    return updated;
  });
}

private prepareRowData(data: any) {
  const rows = Array.isArray(data) ? data : [];
  return rows.map(d => {
    const row = this.applyRoyaltyRatesFromLicense(d);
    // Normalize DB flag for manually edited landed cost.
    // Backend column/colId is `rfqItem_is_landed_cost_manual`, which should be returned on each row.
    if (row.rfqItem_is_landed_cost_manual !== undefined) {
      row.rfqItem_is_landed_cost_manual = !!row.rfqItem_is_landed_cost_manual;
    }
    return row;
  });
}

private decrementLoaderIfInitialLoad(): void {
  if (this.isInitialLoad) {
    this.isInitialLoad = false;
    this.loaderService.decrement();
  }
}

