import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable, firstValueFrom, from } from 'rxjs';
import { environment } from 'src/environments/environment';
import { ConfigService } from './config.service';

@Injectable({
  providedIn: 'root'
})
export class CustomerService {
  serverAddress = environment.url;

  customers$: BehaviorSubject<any> = new BehaviorSubject([]);
  constructor(
    private http: HttpClient,
    private configService: ConfigService,
  ) { }

  getColumns(): Observable<any> {
    return this.http.get(`${this.serverAddress}/api/grid/access-level/customer`);
  }

  getCustomers(): Observable<any> {
    return this.http.get(`${this.serverAddress}/api/customers/`);
  }

  updateCustomer(customerId, update): Observable<any> {
    return this.http.patch(`${this.serverAddress}/api/customers/${customerId}`, update);
  }

  createCustomer(data): Observable<any> {
    return this.http.post(`${this.serverAddress}/api/customers/`, data);
  }

  deleteCustomer(id: string): Observable<any> {
    return this.http.delete(`${this.serverAddress}/api/customers/${id}`);
  }

  loadData(): void {
    this.getCustomers().subscribe(value => {
      this.customers$.next(value);
    })
  }

  /** Upload a logo file to S3 and save the resulting URL to the customer record. */
  uploadLogo(customerId: number, file: File): Observable<string> {
    const extension = file.name.split('.').pop()?.toLowerCase() ?? '';
    const fileName = `images-customer-logo-${customerId}-${Date.now()}.${extension}`;
    // file.type can be empty on some Windows browsers for webp and other formats
    const MIME_MAP: Record<string, string> = {
      jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png',
      gif: 'image/gif', webp: 'image/webp', svg: 'image/svg+xml',
      avif: 'image/avif', bmp: 'image/bmp'
    };
    const contentType = file.type || MIME_MAP[extension] || 'application/octet-stream';
    return from(this._doLogoUpload(customerId, file, fileName, contentType));
  }

  private async _doLogoUpload(customerId: number, file: File, fileName: string, contentType: string): Promise<string> {
    const res: any = await firstValueFrom(
      this.http.post(`${this.serverAddress}/getPreSignedUrl`, { fileName, contentType })
    );
    const uploadRes = await fetch(res.signedUrl, { method: 'PUT', body: file, headers: { 'Content-Type': contentType } });
    if (!uploadRes.ok) {
      throw new Error(`S3 upload failed: ${uploadRes.status}`);
    }
    const { publicUrl } = await firstValueFrom(
      this.http.post<{ publicUrl: string }>(`${this.serverAddress}/setObjectPublic`, { fileName })
    );
    await firstValueFrom(this.updateCustomer(customerId, { customers_logo: publicUrl }));
    return publicUrl;
  }

  createView(): void {

  }
}
