// CACHED (added 2026-06-22): the RFQ detail renderer called this on every
// master-row expansion. The factory→country map is static for a session, so
// memoize the single response. Call clearFactoryCountryMapCache() if factory
// countries are edited mid-session. To UNDO: delete the cache field + this memo
// and return the plain http.get (see docs/performance-caching.md).
private factoryCountryMap$?: Observable<{ map: Record<string, string> }>;
getFactoryCountryMap(): Observable<{ map: Record<string, string> }> {
  if (!this.factoryCountryMap$) {
    this.factoryCountryMap$ = this.http.get<{ map: Record<string, string> }>(
      `${this.base}/api/admin/factories/countries`,
    ).pipe(
      catchError((err) => { this.factoryCountryMap$ = undefined; return of({ map: {} }); }),
      shareReplay({ bufferSize: 1, refCount: false }),
    );
  }
  return this.factoryCountryMap$;
}
/** Drop the cached factory→country map so the next read re-fetches. */
clearFactoryCountryMapCache(): void {
  this.factoryCountryMap$ = undefined;
}

