ngOnInit() {
  // Start loader immediately to prevent blank page flash
  this.loaderService.increment();

  this.authService.getUserFromToken().then((user: any) => {
    this.currentUserId = user?.user_id ?? null;
  });

  this.setupVendorSubscription();
  this.loadInitialMetadata();
}

// PERF (2026-06-22): the init data used to load as a SERIAL HTTP waterfall:
//   verifyRole → getCompanyCode → getRFQItemStatus → {RFQGroup, customers,
//   delivery, steps} → (in afterMetadataReady) getLicenseList → getCBM →
//   getAllRFQItem.
// Time-to-grid was therefore the SUM of all those round trips. These reference
// lookups are independent of one another, so we now fire them together with
// forkJoin and only chain getAllRFQItem (which needs role + division +
// status) after they all resolve.
//
// Each inner stream has its own catchError(() => of(default)) because forkJoin
// errors (and emits nothing) if ANY inner observable errors — one failed
// lookup must not blank the whole page. This also removes a latent race the old
// code had: licenseRateMap is now guaranteed populated before getAllRFQItem
// processes rows (previously getLicenseList + getAllRFQItem were both fired
// inside afterMetadataReady with no ordering guarantee).
//
// >>> HOW TO UNDO: restore the serial chain — ngOnInit() called verifyRole() +
//     loadCompanyCode(); loadCompanyCode → loadRFQStatuses → afterMetadataReady,
//     and afterMetadataReady called getLicenseList()/getCBM(). The original
//     methods are in git history for this file. See
//     docs/performance-caching.md §"Reverting the RFQ forkJoin".
private loadInitialMetadata(): void {
  forkJoin({
    role: this.itemService.verifyRole().pipe(catchError(() => of(null))),
    company: this.itemService.getCompanyCode().pipe(catchError(() => of([]))),
    status: this.itemService.getRFQItemStatus().pipe(catchError(() => of([]))),
    rfqGroup: this.itemService.getRFQGroup().pipe(catchError(() => of([]))),
    customers: this.itemService.getCustomers().pipe(catchError(() => of([]))),
    delivery: this.itemService.getDeliveryLocation().pipe(catchError(() => of([]))),
    steps: this.itemService.getRFQStep().pipe(catchError(() => of([]))),
    licenses: this.itemService.getLicenseList().pipe(catchError(() => of([]))),
    cbm: this.itemService.getCBM().pipe(catchError(() => of([]))),
