import { AfterViewInit, Component, ElementRef, OnInit, ViewChild, Inject } from '@angular/core';
import { MatDialog as MatDialog, MatDialogRef as MatDialogRef, MAT_DIALOG_DATA as MAT_DIALOG_DATA } from '@angular/material/dialog';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar as MatSnackBar } from '@angular/material/snack-bar';
import { FormBuilder, UntypedFormGroup, Validators, UntypedFormControl, FormGroupDirective, NgForm } from '@angular/forms';
import { Observable } from 'rxjs';
import { firstValueFrom } from 'rxjs';
import { map, startWith } from 'rxjs/operators';

export interface DialogData {
  containercost: string
}
@Component({
    selector: 'container_cost_dialog',
    templateUrl: 'container_cost_dialog.component.html',
    styleUrls: ['container_cost_dialog.component.scss'],
    standalone: false
})
export class ContainerCostDialogomponent {
  form: UntypedFormGroup;
  myControl = new UntypedFormControl();
  options: any[] = []
  filteredOptions: Observable<any[]>;
  constructor(private itemService: itemService, public dialogRef: MatDialogRef<ContainerCostDialogomponent>,
    @Inject(MAT_DIALOG_DATA) public data: DialogData, public dialog: MatDialog, private _snakcbar: MatSnackBar) {
  }

  async ngOnInit() {
    try {
      const data: any = await firstValueFrom(this.itemService.getCBM());
      for (var i = 0; data.length > i; i++) {
        this.options.push({ title: data[i].RFQContainer_price, id: data[i].RFQContainer_id })
      }
      this.filteredOptions = this.myControl.valueChanges.pipe(
        startWith(''),
        map(value => (typeof value === 'string' ? value : value)),
        map(value => (value ? this._filter(value) : this.options.slice())),
      );
    } catch (err) {
      console.error('[ContainerCostDialog] getCBM failed:', err);
    }
    this.myControl.setValue(this.data.containercost)
  }

  private _filter(value: any): any[] {
    let filterValue;
    if (value.title) {
      filterValue = value.title
    } else {
      filterValue = value
    }
    return this.options.filter(options => options.title === filterValue);
  }

  displayFn(data: any) {
    if (data) {
      if (data.title) {
        return data.title && data.title ? data.title : '';
      } else {
        return data && data ? data : '';
      }
    }
  }
  onSave() {
   
      this.dialogRef.close(this.myControl.value)
    
  }

  onCancel() {
    this.dialogRef.close()
  }

