import { Component } from '@angular/core';
import { MatDialogRef } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { firstValueFrom } from 'rxjs';
import { itemService } from '../../../helpers/services/main.service';

/**
 * Admin-only bulk archive of the oldest N *active* RFQ items.
 *
 * Flow: the admin sets a count (default 1500), runs a PREVIEW (dryRun) to see the
 * exact set that would be archived, then confirms to apply. "Oldest" is resolved
 * server-side by COALESCE(rfqItem_date_modified, rfqItem_created_date) ASC. Archive
 * is the reversible global flag (rfqItem_archive) — items move to the Archive tab,
 * nothing is deleted. Backend: POST /archiveOldestRFQItems (authRole(['admin'])).
 *
 * The dialog closes with `true` only after a successful real archive, so the
 * caller can refresh the grid.
 */
@Component({
  selector: 'archive-oldest-dialog',
  templateUrl: 'archive-oldest-dialog.component.html',
  styleUrls: ['archive-oldest-dialog.component.scss'],
  standalone: false,
})
export class ArchiveOldestDialogComponent {
  /** Matches the backend default (1500) and cap (5000). */
  limit = 1500;
  readonly maxLimit = 5000;

  previewing = false;
  archiving = false;

  /** Populated after a successful preview. null = no preview run yet. */
  preview: { matched: number; items: Array<{ rfqItem_id: number; rfqItem_style_number: string; effective_date: string }> } | null = null;

  constructor(
    private itemService: itemService,
    public dialogRef: MatDialogRef<ArchiveOldestDialogComponent>,
    private _snackBar: MatSnackBar,
  ) {}

  private clampedLimit(): number {
    const n = Math.floor(Number(this.limit));
    if (!Number.isFinite(n) || n <= 0) return 1;
    return Math.min(n, this.maxLimit);
  }

  /** When the count changes, the previous preview no longer matches — invalidate it. */
  onLimitChange(): void {
    this.preview = null;
  }

  async onPreview(): Promise<void> {
    if (this.previewing || this.archiving) return;
    this.previewing = true;
    this.preview = null;
    try {
      const res: any = await firstValueFrom(
        this.itemService.archiveOldestRFQItems({ limit: this.clampedLimit(), dryRun: true }),
      );
      this.preview = {
        matched: res?.matched ?? 0,
        items: Array.isArray(res?.items) ? res.items : [],
      };
    } catch (err) {
      console.error('[ArchiveOldestDialog] preview failed:', err);
      this._snackBar.open('Preview failed. Please try again.', 'Close', { duration: 5000 });
    } finally {
      this.previewing = false;
    }
  }

  async onArchive(): Promise<void> {
    if (this.archiving || this.previewing || !this.preview || this.preview.matched === 0) return;
    this.archiving = true;
    try {
      const res: any = await firstValueFrom(
        this.itemService.archiveOldestRFQItems({ limit: this.clampedLimit(), dryRun: false }),
      );
      const archived = res?.archived ?? 0;
      this._snackBar.open(`Archived ${archived} RFQ item${archived === 1 ? '' : 's'}.`, 'Close', { duration: 5000 });
      this.dialogRef.close(true); // signal the caller to refresh the grid
    } catch (err) {
      console.error('[ArchiveOldestDialog] archive failed:', err);
      this._snackBar.open('Archive failed. No items were archived.', 'Close', { duration: 5000 });
      this.archiving = false; // keep the dialog open so they can retry
    }
  }

  onCancel(): void {
    this.dialogRef.close(false);
  }
}

