.archive-oldest-content {
  min-width: 420px;
  max-width: 560px;
}

.archive-oldest-help {
  margin: 0 0 16px;
  color: var(--text-secondary, rgba(0, 0, 0, 0.6));
  font-size: 13px;
  line-height: 1.5;
}

.archive-oldest-count {
  width: 180px;
}

.archive-oldest-actions-row {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
}

.archive-oldest-preview-note {
  font-size: 12px;
  color: var(--text-secondary, rgba(0, 0, 0, 0.6));
}

.archive-oldest-summary {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 4px 0 12px;
  font-size: 14px;
}

.archive-oldest-empty {
  margin: 8px 0;
  font-size: 14px;
  color: var(--text-secondary, rgba(0, 0, 0, 0.6));
}

.archive-oldest-table-wrap {
  max-height: 280px;
  overflow-y: auto;
  border: 1px solid var(--divider, rgba(0, 0, 0, 0.12));
  border-radius: 6px;
}

.archive-oldest-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;

  thead th {
    position: sticky;
    top: 0;
    background: var(--surface, #fafafa);
    text-align: left;
    padding: 8px 12px;
    font-weight: 600;
    border-bottom: 1px solid var(--divider, rgba(0, 0, 0, 0.12));
  }

  tbody td {
    padding: 6px 12px;
    border-bottom: 1px solid var(--divider, rgba(0, 0, 0, 0.06));
  }

  tbody tr:last-child td {
    border-bottom: none;
  }
}

