import { of, throwError } from 'rxjs';
import { ArchiveOldestDialogComponent } from './archive-oldest-dialog.component';

describe('ArchiveOldestDialogComponent', () => {
  let itemService: any;
  let dialogRef: { close: jest.Mock };
  let snackBar: { open: jest.Mock };
  let component: ArchiveOldestDialogComponent;

  beforeEach(() => {
    itemService = { archiveOldestRFQItems: jest.fn() };
    dialogRef = { close: jest.fn() };
    snackBar = { open: jest.fn() };
    component = new ArchiveOldestDialogComponent(itemService, dialogRef as any, snackBar as any);
  });

  it('defaults limit to 1500', () => {
    expect(component.limit).toBe(1500);
  });

  it('preview calls the service with dryRun:true and stores the matched set', async () => {
    itemService.archiveOldestRFQItems.mockReturnValue(
      of({ matched: 2, items: [{ rfqItem_id: 1, rfqItem_style_number: 'A', effective_date: '2024-01-01' }] }),
    );

    await component.onPreview();

    expect(itemService.archiveOldestRFQItems).toHaveBeenCalledWith({ limit: 1500, dryRun: true });
