    expect(dialogRef.close).not.toHaveBeenCalled();
    expect(component.archiving).toBe(false);
    expect(snackBar.open).toHaveBeenCalled();
  });

  it('cancel closes with false', () => {
    component.onCancel();
    expect(dialogRef.close).toHaveBeenCalledWith(false);
  });
});

