import { describe, expect, test, beforeEach, jest } from '@jest/globals';
import { of, throwError } from 'rxjs';
import { ArchiveOldestDialogComponent } from './archive-oldest-dialog.component';

describe('ArchiveOldestDialogComponent', () => {
  let archiveOldestRFQItems: jest.Mock;
  let dialogRef: { close: jest.Mock };
  let snackBar: { open: jest.Mock };
  let component: ArchiveOldestDialogComponent;

  beforeEach(() => {
    archiveOldestRFQItems = jest.fn();
    dialogRef = { close: jest.fn() };
    snackBar = { open: jest.fn() };
    component = new ArchiveOldestDialogComponent(
      { archiveOldestRFQItems } as any,
      dialogRef as any,
      snackBar as any,
    );
  });

  test('defaults to a limit of 1500', () => {
    expect(component.limit).toBe(1500);
  });

  test('preview requests dryRun:true with the clamped limit and stores the result', async () => {
    component.limit = 9999; // above the 5000 cap
    archiveOldestRFQItems.mockReturnValue(of({
      dryRun: true, matched: 2,
      items: [
        { rfqItem_id: 1, rfqItem_style_number: 'A', effective_date: '2024-01-01' },
        { rfqItem_id: 2, rfqItem_style_number: 'B', effective_date: '2023-01-01' },
      ],
    }));

    await component.onPreview();

    expect(archiveOldestRFQItems).toHaveBeenCalledWith({ limit: 5000, dryRun: true });
    expect(component.preview?.matched).toBe(2);
    expect(component.preview?.items.length).toBe(2);
    expect(component.previewing).toBe(false);
  });

  test('changing the limit invalidates a prior preview', () => {
    component.preview = { matched: 5, items: [] };
    component.onLimitChange();
    expect(component.preview).toBeNull();
  });

  test('archive does nothing until a non-empty preview exists', async () => {
    component.preview = null;
    await component.onArchive();
    expect(archiveOldestRFQItems).not.toHaveBeenCalled();

    component.preview = { matched: 0, items: [] };
    await component.onArchive();
    expect(archiveOldestRFQItems).not.toHaveBeenCalled();
  });

  test('archive sends dryRun:false and closes with true on success', async () => {
    component.limit = 1500;
    component.preview = { matched: 3, items: [] };
    archiveOldestRFQItems.mockReturnValue(of({ dryRun: false, archived: 3 }));

    await component.onArchive();

    expect(archiveOldestRFQItems).toHaveBeenCalledWith({ limit: 1500, dryRun: false });
    expect(dialogRef.close).toHaveBeenCalledWith(true);
  });

  test('archive failure keeps the dialog open and does not close with true', async () => {
    component.preview = { matched: 3, items: [] };
    archiveOldestRFQItems.mockReturnValue(throwError(() => new Error('boom')));

    await component.onArchive();

    expect(dialogRef.close).not.toHaveBeenCalled();
    expect(component.archiving).toBe(false);
    expect(snackBar.open).toHaveBeenCalled();
  });

  test('cancel closes with false', () => {
    component.onCancel();
    expect(dialogRef.close).toHaveBeenCalledWith(false);
  });
});

