import { TestBed } from '@angular/core/testing';
import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
import { itemService } from './main.service';
import { environment } from '../../../environments/environment';

// Focused tests for the reference-data caching layer added 2026-06-22
// (getCached / clearRefCache + per-mutation invalidation). See docs/performance-caching.md.
describe('itemService reference-data cache', () => {
  const base = environment.url;
  let service: itemService;
  let httpMock: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [HttpClientTestingModule],
      providers: [itemService],
    });
    service = TestBed.inject(itemService);
    httpMock = TestBed.inject(HttpTestingController);
  });

  afterEach(() => httpMock.verify());

  it('caches: two subscribers trigger only ONE HTTP request', () => {
    let a: any, b: any;
    service.getRFQItemStatus().subscribe((v) => (a = v));
    service.getRFQItemStatus().subscribe((v) => (b = v));

    const req = httpMock.expectOne(`${base}/findRFQItemStatus`);
    req.flush([{ id: 1 }]);

    expect(a).toEqual([{ id: 1 }]);
    expect(b).toEqual([{ id: 1 }]);
    httpMock.expectNone(`${base}/findRFQItemStatus`); // no second request
  });

  it('replays the cache on later reads without re-fetching', () => {
    service.getRFQItemStatus().subscribe();
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush([{ id: 1 }]);

    let later: any;
    service.getRFQItemStatus().subscribe((v) => (later = v));
    httpMock.expectNone(`${base}/findRFQItemStatus`);
    expect(later).toEqual([{ id: 1 }]);
  });

  it('hands each subscriber a defensive shallow copy (mutation cannot corrupt the cache)', () => {
    let a: any[] = [], b: any[] = [];
    service.getRFQItemStatus().subscribe((v) => (a = v));
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush([{ id: 1 }]);
    a.push({ id: 999 }); // mutate first subscriber's copy

    service.getRFQItemStatus().subscribe((v) => (b = v));
    expect(b.length).toBe(1); // cache untouched
  });

  it('clearRefCache forces the next read to re-fetch', () => {
    service.getRFQItemStatus().subscribe();
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush([{ id: 1 }]);

    service.clearRefCache('rfq_item_status');

    service.getRFQItemStatus().subscribe();
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush([{ id: 2 }]); // re-fetched
  });

  it('does NOT cache errors — a failed fetch is retried on the next read', () => {
    service.getRFQItemStatus().subscribe({ next: () => {}, error: () => {} });
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush('boom', { status: 500, statusText: 'Server Error' });

    // entry was evicted on error → next read issues a fresh request
    service.getRFQItemStatus().subscribe({ next: () => {}, error: () => {} });
    httpMock.expectOne(`${base}/findRFQItemStatus`).flush([{ id: 1 }]);
  });

  it('addNewRFQGroup invalidates the rfq_group cache', () => {
    service.getRFQGroup().subscribe();
    httpMock.expectOne((r) => r.url === `${base}/getRFQGroup`).flush([{ RFQGroup_name: 'X' }]);

    // cached: no new request
    service.getRFQGroup().subscribe();
    httpMock.expectNone((r) => r.url === `${base}/getRFQGroup`);

    // a mutation flushes the cache...
    service.addNewRFQGroup({ name: 'Y' }).subscribe();
    httpMock.expectOne(`${base}/addNewRFQGroup`).flush({ ok: true });

    // ...so the next read re-fetches
    service.getRFQGroup().subscribe();
    httpMock.expectOne((r) => r.url === `${base}/getRFQGroup`).flush([{ RFQGroup_name: 'X' }, { RFQGroup_name: 'Y' }]);
  });

  it('getRFQGroup(showLegacy=true) bypasses the cache', () => {
    service.getRFQGroup(true).subscribe();
    const req = httpMock.expectOne((r) => r.url === `${base}/getRFQGroup`);
    expect(req.request.params.get('showLegacy')).toBe('true');
    req.flush([]);
  });
});

