import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import { of, throwError } from 'rxjs';
import { itemService } from './main.service';

// Focused tests for the reference-data caching layer added 2026-06-22
// (getCached / clearRefCache + per-mutation invalidation). See docs/performance-caching.md.
// This repo's jest setup constructs services/components directly (no Angular TestBed),
// so we inject a mock HttpClient. Counting http.get/post calls = counting cache misses,
