    service.addNewRFQGroup({ name: 'Y' }).subscribe(); // tap → clearRefCache('rfq_group')

    service.getRFQGroup().subscribe();
    expect(http.get).toHaveBeenCalledTimes(2); // re-fetched after invalidation
