}
```

**prod_tracking** (designflow-frontend/src/app/pages/prod_tracking/prod_tracking.component.ts:206-261):
```typescript
gridOptions = {
  rowSelection: { mode: 'multiRow' },
  masterDetail: true,
  detailRowAutoHeight: true,
  rowModelType: 'serverSide',
  cacheBlockSize: 100,
  maxBlocksInCache: 10,
  blockLoadDebounceMillis: 500,
  animateRows: false,
  loading: true,
  suppressLoadingOverlay: true,
  detailCellRendererParams: {
    getDetailRowData: (params) => {
      params.successCallback(params.data.details || params.data.ProdOrderDetails || []);
    },
  },
  // ... other options
}
```

**licensing_tracking** (designflow-frontend/src/app/pages/licensing_tracking/licensing_tracking.component.ts:217-257):
```typescript
gridOptions = {
  masterDetail: true,
  rowModelType: 'serverSide',
  rowSelection: { mode: 'multiRow' },
  cacheBlockSize: 100,
  maxBlocksInCache: 10,
  blockLoadDebounceMillis: 500,
  animateRows: true,
  loading: true,
  suppressLoadingOverlay: true,
  // ... other options
}
```

**Key differences:**
- itemLibrary uses **pagination: true** with explicit paginationPageSizeSelector; prod_tracking and licensing_tracking rely on caching without explicit pagination flag
- prod_tracking has **masterDetail: true** with detail-row-data callback; licensing_tracking has masterDetail but no explicit detail config
- All three use identical **cacheBlockSize: 100, maxBlocksInCache: 10**

---

### DATASOURCE CREATION & getRows IMPLEMENTATION

**itemLibrary** (designflow-frontend/src/app/pages/itemLibrary/itemLibrary.component.ts:769-825):
```typescript
createServerSideDatasource(divisionCodeIds: number[]): IServerSideDatasource {
  const isArchive = this.currentUrl === 'archive';
  if (divisionCodeIds.length === 0) {
    divisionCodeIds = this.selectedDivisionCode?.map(d => d.divCode_id) || [];
  }
  return {
    getRows: (params: IServerSideGetRowsParams) => {
      const request = {
        startRow: params.request.startRow,
        endRow: params.request.endRow,
        filterModel: {
          ...(params.request.filterModel || {}),
          ...(this.tagsQuery ? { tags: { type: 'contains', filter: this.tagsQuery } } : {})
        },
        isArchive,
        divisionCodeIds
      };

      this.ItemLibraryService.getAllitems(request).subscribe({
        next: async (res: any) => {
          const rowData = res.rows || [];
          const totalCount = res.totalCount ?? rowData.length;

          this.rowData = rowData;
          this.totalRowCount = totalCount;

          const statusPanelComp = this.gridApi.getStatusPanel('customTotalCount');
          if (statusPanelComp) {
            (statusPanelComp as any).setTotalCount(totalCount);
          }

          this.gridApi.setGridOption("loading", false);
          this.decrementLoaderIfNeeded();

          params.success({
            rowData,
            rowCount: totalCount,
          });

          mergePreloadCellNotes(this.itemLibraryCellNotes, rowData, 'id');
          this.restoreStateFromSession();
        },
        error: (error) => {
