ItemLibrary.getAllitems = async (req, result) => {
  const { startRow, endRow, filterModel } = req.query;
  const limit = endRow - startRow;
  const offset = Number(startRow);
  const isArchive = req.query.isArchive === 'true';

  try {
    const filters = filterModel ? JSON.parse(filterModel) : {};

    // Normalize multi-filters
    Object.keys(filters).forEach(field => {
      if (filters[field]?.filterType === 'multi') {
        const validSubFilter = filters[field].filterModels.find(sub => sub);
        filters[field] = validSubFilter || null;
      }
    });

    const whereClause = {
      is_item_active: isArchive ? false : { [Op.or]: ['true', null] }
    };

    const tagsConditions = [];
    const merchGroupFilters = { merchGroup01: {}, merchGroup02: {}, ... };

    // Filter translation: agTextColumnFilter.contains → Op.iLike '%value%'
    const buildCondition = (filterDef, dbField) => {
      const value = typeof filterDef.filter === 'string' ? filterDef.filter : '';
      switch (filterDef.type) {
        case 'contains': return { [Op.iLike]: `%${value}%` };
        case 'notContains': return { [Op.notILike]: `%${value}%` };
        case 'equals': return { [Op.eq]: filterDef.filter };
        case 'notEqual': return { [Op.ne]: filterDef.filter };
        case 'startsWith': return { [Op.iLike]: `${value}%` };
        case 'endsWith': return { [Op.iLike]: `%${value}` };
        default: return null;
      }
    };

    // Tag-based filtering with multi-term OR search
    if (dbField === 'tags' && value) {
      const terms = value.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
      if (terms.length > 1) {
        return { [Op.or]: terms.map(t => ({ [Op.iLike]: `%${t}%` })) };
      }
    }

    // Division code filtering
    const divisionCodeIds = req.query.divisionCodeIds ? JSON.parse(req.query.divisionCodeIds) : [];
    if (divisionCodeIds.length > 0) {
      divisionCodeIds.push(2);
      andConditions.push({
        [Op.or]: [
          { div_code_fk: { [Op.in]: divisionCodeIds } },
          { div_code_fk: null }
        ]
      });
    }

    // Query 1: Count (with distinct)
    const count = await sql.itemHeader.count({
      where: whereClause,
      include: merchIncludes,
      distinct: true,
      col: 'item_id_pk'
    });

    // Query 2: Paginated rows (limit/offset)
    const rows = await sql.itemHeader.findAll({
      attributes: [...],
      where: whereClause,
      order: [['item_id_pk', 'DESC'], ['created_time_date', 'DESC'], ...],
      limit,
      offset,
      include: [...]
    });

    // Response
    result(null, {
      rows: remappedData,
      totalCount: count
    });
  } catch (err) {
    result(null, err);
  }
};
